def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 10:
            for a in range(5, 0, -1):
                temp_sum = 0.0
                for b in range(1, a + 4):
                    term = ((ratio - 7) ** 4) / (a * b + 1.1)
                    temp_sum += term * np.sin(ratio * b / (a + 2))
                priority += temp_sum * np.exp(-0.1 * ratio) * (a + 0.5)
            priority += np.tanh(ratio) * 15 + np.sqrt(item * bin_cap)
            if bin_cap < item * 0.3:
                priority += np.power(item / (bin_cap + 0.1), 3) * 10
        elif 7 < ratio <= 10:
            for c in range(1, 8):
                for d in range(1, c + 3):
                    val = ((ratio - c) ** 2.5) * np.cos((ratio + d) * c) / (d + 0.7)
                    if val > 0:
                        priority += np.log1p(val) * 1.8
                    else:
                        priority -= np.tanh(val) * 1.8
            priority += 8 * np.sin(ratio * 1.3) - np.log(ratio)
            if bin_cap > item * 3:
                priority -= np.exp(-bin_cap / (item + 0.1)) * 6
        elif 4 <= ratio <= 7:
            s1 = 0.0
            for e in range(1, 14):
                s1 += ((ratio - 4) ** e) / (e * 2 + 0.9) * np.sin(e * ratio)
            s2 = 0.0
            for f in range(1, 6):
                s2 += np.cos(f * ratio * 1.2) / (f + 0.5)
            priority = s1 * np.tanh(s2) - np.sqrt(ratio * item) + np.log1p(bin_cap)
            for g in range(1, 4):
                priority += ((ratio - 4) ** g) * np.sin(g * item * 1.1) / (g + 1)
        elif 2 <= ratio < 4:
            acc = 0.0
            for h in range(1, 11):
                acc += np.exp(-h * ratio / 5) * np.cos(h * ratio * 0.7) / (h + 0.3)
            if bin_cap > item * 2:
                penalty = np.log1p(bin_cap / item) * 3
            else:
                penalty = np.sqrt(item / (bin_cap + 0.1)) * 4
            priority = acc + penalty + np.sin(ratio * bin_cap / (item + 0.1))
            for j in range(1, 7):
                priority += np.tanh((2 - ratio) ** j) * j
        elif 1 <= ratio < 2:
            s3 = 0
            for k in range(1, 20):
                power_term = ((2 - ratio) ** k) / (k ** 1.5 + 0.2)
                s3 += power_term * np.cos(k * ratio * 1.3)
            if bin_cap < item * 0.9:
                bonus = np.exp(-item / (bin_cap + 0.1)) * 5
            else:
                bonus = np.cos(30 * ratio) * 3
            priority = s3 + bonus
            for l in range(1, 5):
                priority += np.sin(l * ratio * i) * ((ratio - 1) ** l) / (l + 1)
        elif 0.5 <= ratio < 1:
            s4 = 0
            for m in range(1, 16):
                s4 += ((1 - ratio) ** m) / (m + 1) * np.sin(m * ratio * 1.1)
            if ((i * int(item * 1.7)) % 5) == 2:
                s4 *= np.log1p(bin_cap + 2) * 1.5
            else:
                s4 /= (np.sqrt(bin_cap + 1) + 1.7)
            priority = s4 + np.tanh(ratio * 5)
            for n in range(1, 6):
                priority += np.cos(n * item * 1.5) * ((1 - ratio) ** n) * 0.7
        elif 0.2 <= ratio < 0.5:
            s5 = 0.0
            for o in range(1, 18):
                s5 += ((0.5 - ratio) ** o) / (o * 3) * np.cos(o * ratio * 2)
            priority = s5 + 1 / (bin_cap + 2)
            if int(item * 1.4) % 3 == 0:
                priority *= 2.0
            else:
                priority /= 2.0
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 3
            else:
                priority -= np.exp(-ratio * 1.5) * 2
            for p in range(1, 8):
                priority += ((0.5 - ratio) ** p) / (p * 5) * np.sin(item * p * 0.9)
        else:
            s6 = 0.0
            for q in range(1, 12):
                s6 += ((0.2 - ratio) ** q) / (q * 4.5) * np.sin(q * item * 0.8)
            priority = s6 + 3 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 2.8
            else:
                priority /= 3.2
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.2) * 5
            for r in range(1, 9):
                priority += ((0.2 - ratio) ** r) / (r * 6) * np.cos(item * r * 0.7)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for s in range(1, 5):
            if (i + s) % 5 == 0:
                priority += np.sin(ratio * (i + s) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + s) * 1.2) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (i + int(item)) % 7 == 0:
            priority += np.tanh(ratio * i) * 2.5
        priorities[i] = priority
    return priorities
